/*!id: jdt.internal.fix.convertloopfix.to.core.wrapped*/
/*!description: Updates internal JDT UI cleanup to use ConvertLoopFixCore wrapped in CleanUpFixWrapper.*/
/*!severity: info*/
org.eclipse.jdt.internal.corext.fix.ConvertLoopFix.createCleanUp($compilationUnit, $convertForLoops, $convertForLoops2, $useFinal, $checkIfLoopVarUsed)
=> org.eclipse.jdt.internal.ui.fix.CleanUpFixWrapper.create(org.eclipse.jdt.internal.corext.fix.ConvertLoopFixCore.createCleanUp($compilationUnit, $convertForLoops, $convertForLoops2, $useFinal, $checkIfLoopVarUsed))
;;

