@id: jdt.internal.newcuusingwizardproposal.add-semantic-highlighting-flag.package
@severity: info
new org.eclipse.jdt.internal.ui.text.correction.proposals.NewCUUsingWizardProposal($cu, $node, $typeKind, $typeContainer, $superType, $severity) :: instanceof($typeContainer, "org.eclipse.jdt.core.IPackageFragment")
=> new org.eclipse.jdt.internal.ui.text.correction.proposals.NewCUUsingWizardProposal($cu, $node, $typeKind, $typeContainer, $superType, $severity, true)
;;

@id: jdt.internal.newcuusingwizardproposal.add-semantic-highlighting-flag.type
@severity: info
new org.eclipse.jdt.internal.ui.text.correction.proposals.NewCUUsingWizardProposal($cu, $node, $typeKind, $typeContainer, $superType, $severity) :: instanceof($typeContainer, "org.eclipse.jdt.core.IType")
=> new org.eclipse.jdt.internal.ui.text.correction.proposals.NewCUUsingWizardProposal($cu, $node, $typeKind, $typeContainer, $superType, $severity, false)
;;

org.eclipse.swt.widgets.TabFolder
=> org.eclipse.swt.custom.CTabFolder
;;

org.eclipse.swt.widgets.TabItem
=> org.eclipse.swt.custom.CTabItem
;;

new org.eclipse.swt.widgets.TabFolder($composite, $style)
=> new org.eclipse.swt.custom.CTabFolder($composite, $style)
;;

new org.eclipse.swt.widgets.TabItem($folder, $style)
=> new org.eclipse.swt.custom.CTabItem($folder, $style)
;;
